import { task, batch } from "@trigger.dev/sdk";

const TRIAL_ID = "parallel_batch_trigger__tD9PeGv";

// Child task that accepts a number, waits for 2 seconds, and returns the number squared
export const childTask = task({
  id: `childTask-${TRIAL_ID}`,
  run: async (payload: { number: number }) => {
    // Wait for 2 seconds
    await new Promise((resolve) => setTimeout(resolve, 2000));

    // Return the number squared
    return payload.number * payload.number;
  },
});

// Parent task that accepts an array of numbers and triggers childTask for each in parallel
export const parentTask = task({
  id: `parentTask-${TRIAL_ID}`,
  run: async (payload: { numbers: number[] }) => {
    // Trigger childTask for each number in parallel using batch.triggerByTaskAndWait
    const results = await batch.triggerByTaskAndWait(
      payload.numbers.map((number) => ({
        task: childTask,
        payload: { number },
      }))
    );

    // Unwrap the results and return an array of squared numbers
    const squaredNumbers = results.map((result) => {
      if (result.ok) {
        return result.output;
      } else {
        // Handle error case - could throw or return a default value
        throw new Error(`Child task failed: ${result.error}`);
      }
    });

    return squaredNumbers;
  },
});

